const schemaRows = $('Scan DB Structure').all();
const directiveRows = $('Get Directives').all();
const directives = directiveRows.length > 0 ? directiveRows.map((r, i) => (i + 1) + '. ' + r.json.directive).join('\n') : 'No directives provided.';

if (schemaRows.length === 0) {
  return [{ json: { text: 'No database tables found.', directives } }];
}

const schemas = {};
schemaRows.forEach(row => {
  const d = row.json;
  if (!schemas[d.schema_name]) {
    schemas[d.schema_name] = {};
  }
  if (!schemas[d.schema_name][d.table_name]) {
    schemas[d.schema_name][d.table_name] = [];
  }
  schemas[d.schema_name][d.table_name].push({
    column: d.column_name,
    type: d.data_type,
    description: d.column_description || ''
  });
});

let text = 'PostgreSQL Database Schema and Column Documentation:\n\n';
for (const [schemaName, tables] of Object.entries(schemas)) {
  text += `Schema: ${schemaName}\n`;
  for (const [tableName, columns] of Object.entries(tables)) {
    text += `  Table: ${tableName}\n`;
    columns.forEach(col => {
      text += `    - ${col.column} (${col.type})${col.description ? ' // ' + col.description : ''}\n`;
    });
  }
  text += '\n';
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/kowalski.md', 'utf8');
} catch (e) {
  persona = 'Kowalski, tactical and military-grade database analyst agent.';
}

return [{ json: { text, directives, kowalski_persona: persona } }];

const { Client } = require('pg');
const client = new Client({
  host: process.env.DB_APPLICATION_HOST || process.env.DB_POSTGRESDB_HOST || 'db',
  port: parseInt(process.env.DB_APPLICATION_PORT || process.env.DB_POSTGRESDB_PORT || '5432', 10),
  database: 'jager',
  user: process.env.DB_APPLICATION_USER || process.env.DB_POSTGRESDB_USER || 'jager',
  password: process.env.DB_APPLICATION_PASSWORD || process.env.DB_POSTGRESDB_PASSWORD || 'jager',
});
await client.connect();
try {
  const res = await client.query(query);
  await client.end();
  return JSON.stringify(res.rows);
} catch (err) {
  await client.end();
  return JSON.stringify({ error: err.message });
}
